import React, { useState, useEffect } from 'react';
import Lottie from 'lottie-react';
import './App.css';

const lottieUrls = [
  `${process.env.PUBLIC_URL}/lotties/holding-stage.json`,
  `${process.env.PUBLIC_URL}/lotties/display-period.json`,
  `${process.env.PUBLIC_URL}/lotties/open-trading.json`,
  `${process.env.PUBLIC_URL}/lotties/now-trading.json`,
  `${process.env.PUBLIC_URL}/lotties/pre-launch.json`
];

function App() {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [animationData, setAnimationData] = useState(null);

  useEffect(() => {
    console.log('Attempting to load:', lottieUrls[currentIndex]);
    fetch(lottieUrls[currentIndex])
      .then(response => {
        console.log('Response status:', response.status);
        if (!response.ok) {
          throw new Error(`HTTP error! status: ${response.status}`);
        }
        return response.json();
      })
      .then(data => {
        console.log('Animation loaded successfully');
        setAnimationData(data);
      })
      .catch(error => console.error('Error loading Lottie:', error));
  }, [currentIndex]);

  const handleClick = () => {
    setCurrentIndex((prevIndex) => (prevIndex + 1) % lottieUrls.length);
  };

  return (
    <div className="App" onClick={handleClick}>
      <div className="lottie-container">
        {animationData && (
          <Lottie 
            animationData={animationData} 
            loop={true}
          />
        )}
      </div>
    </div>
  );
}

export default App;
